import{_ as a,o as s,c as o,ae as i}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"Podman","description":"루트리스 Podman 컨테이너에서 OpenClaw 실행","frontmatter":{"title":"Podman","description":"루트리스 Podman 컨테이너에서 OpenClaw 실행"},"headers":[],"relativePath":"install/podman.md","filePath":"install/podman.md","lastUpdated":null}'),l={name:"install/podman.md"};function d(n,e,t,c,p,h){return s(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="podman" tabindex="-1">Podman <a class="header-anchor" href="#podman" aria-label="Permalink to &quot;Podman&quot;">​</a></h1><p>현재 비루트 사용자가 관리하는 루트리스 Podman 컨테이너에서 OpenClaw Gateway를 실행합니다.</p><p>의도된 모델:</p><ul><li>Podman이 게이트웨이 컨테이너를 실행합니다.</li><li>호스트 <code>openclaw</code> CLI가 제어 평면입니다.</li><li>지속 상태는 기본적으로 <code>~/.openclaw</code> 아래 호스트에 있습니다.</li><li>일상 관리는 <code>sudo -u openclaw</code>, <code>podman exec</code> 또는 별도의 서비스 사용자 대신 <code>openclaw --container &amp;lt;name&amp;gt; ...</code>를 사용합니다.</li></ul><h2 id="사전-요구-사항" tabindex="-1">사전 요구 사항 <a class="header-anchor" href="#사전-요구-사항" aria-label="Permalink to &quot;사전 요구 사항&quot;">​</a></h2><ul><li>루트리스 모드의 <strong>Podman</strong></li><li>호스트에 설치된 <strong>OpenClaw CLI</strong></li><li><strong>선택적:</strong> Quadlet 관리 자동 시작을 원하면 <code>systemd --user</code></li><li><strong>선택적:</strong> 헤드리스 호스트에서 부팅 지속성을 위해 <code>loginctl enable-linger &quot;$(whoami)&quot;</code>를 원하는 경우에만 <code>sudo</code></li></ul><h2 id="빠른-시작" tabindex="-1">빠른 시작 <a class="header-anchor" href="#빠른-시작" aria-label="Permalink to &quot;빠른 시작&quot;">​</a></h2><ol><li><p><strong>일회성 설정</strong></p><p>저장소 루트에서 <code>./scripts/podman/setup.sh</code>를 실행합니다.</p></li><li><p><strong>Gateway 컨테이너 시작</strong></p></li></ol><p><code>./scripts/run-openclaw-podman.sh launch</code>로 컨테이너를 시작합니다.</p><ol start="3"><li><strong>컨테이너 내에서 온보딩 실행</strong></li></ol><p><code>./scripts/run-openclaw-podman.sh launch setup</code>을 실행한 다음 <code>http://127.0.0.1:18789/</code>를 엽니다.</p><ol start="4"><li><strong>호스트 CLI에서 실행 중인 컨테이너 관리</strong></li></ol><p><code>OPENCLAW_CONTAINER=openclaw</code>를 설정한 다음 호스트에서 일반 <code>openclaw</code> 명령을 사용합니다.</p><p>설정 세부 사항:</p><ul><li><code>./scripts/podman/setup.sh</code>는 기본적으로 루트리스 Podman 저장소에 <code>openclaw:local</code>을 빌드하거나 <code>OPENCLAW_IMAGE</code> / <code>OPENCLAW_PODMAN_IMAGE</code>를 설정한 경우 사용합니다.</li><li>없는 경우 <code>gateway.mode: &quot;local&quot;</code>이 포함된 <code>~/.openclaw/openclaw.json</code>을 생성합니다.</li><li>없는 경우 <code>OPENCLAW_GATEWAY_TOKEN</code>이 포함된 <code>~/.openclaw/.env</code>를 생성합니다.</li><li>수동 실행의 경우 헬퍼는 <code>~/.openclaw/.env</code>에서 Podman 관련 키의 소규모 허용 목록만 읽고 컨테이너에 명시적 런타임 환경 변수를 전달합니다. 전체 환경 파일을 Podman에 넘기지 않습니다.</li></ul><p>Quadlet 관리 설정:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/podman/setup.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --quadlet</span></span></code></pre></div><p>Quadlet은 systemd 사용자 서비스에 의존하기 때문에 Linux 전용 옵션입니다.</p><p><code>OPENCLAW_PODMAN_QUADLET=1</code>을 설정할 수도 있습니다.</p><p>선택적 빌드/설정 환경 변수:</p><ul><li><code>OPENCLAW_IMAGE</code> 또는 <code>OPENCLAW_PODMAN_IMAGE</code> -- <code>openclaw:local</code>을 빌드하는 대신 기존/가져온 이미지 사용</li><li><code>OPENCLAW_DOCKER_APT_PACKAGES</code> -- 이미지 빌드 중 추가 apt 패키지 설치</li><li><code>OPENCLAW_EXTENSIONS</code> -- 빌드 시 확장 종속성 미리 설치</li></ul><p>컨테이너 시작:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/run-openclaw-podman.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span></span></code></pre></div><p>스크립트는 <code>--userns=keep-id</code>를 사용하여 현재 uid/gid로 컨테이너를 시작하고 OpenClaw 상태를 컨테이너에 바인드 마운트합니다.</p><p>온보딩:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/run-openclaw-podman.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>그런 다음 <code>http://127.0.0.1:18789/</code>를 열고 <code>~/.openclaw/.env</code>의 토큰을 사용합니다.</p><p>호스트 CLI 기본값:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OPENCLAW_CONTAINER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">openclaw</span></span></code></pre></div><p>그러면 다음과 같은 명령들이 해당 컨테이너 내에서 자동으로 실행됩니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dashboard</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-open</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --deep</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 추가 서비스 스캔 포함</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span></code></pre></div><p>macOS에서 Podman 머신은 브라우저가 게이트웨이에 비로컬로 보이게 할 수 있습니다. 실행 후 Control UI에서 장치 인증 오류가 보고되면 <a href="#podman--tailscale">Podman + Tailscale</a>의 Tailscale 가이던스를 사용합니다.</p><p><a id="podman--tailscale"></a></p><h2 id="podman-tailscale" tabindex="-1">Podman + Tailscale <a class="header-anchor" href="#podman-tailscale" aria-label="Permalink to &quot;Podman + Tailscale&quot;">​</a></h2><p>HTTPS 또는 원격 브라우저 액세스를 위해 기본 Tailscale 문서를 따르십시오.</p><p>Podman 특정 참고 사항:</p><ul><li>Podman publish 호스트를 <code>127.0.0.1</code>로 유지합니다.</li><li><code>openclaw gateway --tailscale serve</code>보다 호스트 관리 <code>tailscale serve</code>를 선호합니다.</li><li>macOS에서 로컬 브라우저 장치 인증 컨텍스트가 신뢰할 수 없는 경우 임시 로컬 터널 해결 방법 대신 Tailscale 액세스를 사용합니다.</li></ul><p>참조:</p><ul><li><a href="/openclaw-docs-ko/gateway/tailscale">Tailscale</a></li><li><a href="/openclaw-docs-ko/web/control-ui">Control UI</a></li></ul><h2 id="systemd-quadlet-선택적" tabindex="-1">Systemd (Quadlet, 선택적) <a class="header-anchor" href="#systemd-quadlet-선택적" aria-label="Permalink to &quot;Systemd (Quadlet, 선택적)&quot;">​</a></h2><p><code>./scripts/podman/setup.sh --quadlet</code>을 실행한 경우 설정은 다음 위치에 Quadlet 파일을 설치합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/.config/containers/systemd/openclaw.container</span></span></code></pre></div><p>유용한 명령어:</p><ul><li><strong>시작:</strong> <code>systemctl --user start openclaw.service</code></li><li><strong>중지:</strong> <code>systemctl --user stop openclaw.service</code></li><li><strong>상태:</strong> <code>systemctl --user status openclaw.service</code></li><li><strong>로그:</strong> <code>journalctl --user -u openclaw.service -f</code></li></ul><p>Quadlet 파일 편집 후:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> daemon-reload</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw.service</span></span></code></pre></div><p>SSH/헤드리스 호스트에서 부팅 지속성을 위해 현재 사용자에 대한 링거를 활성화합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> loginctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable-linger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whoami</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)&quot;</span></span></code></pre></div><h2 id="구성-환경-변수-및-스토리지" tabindex="-1">구성, 환경 변수 및 스토리지 <a class="header-anchor" href="#구성-환경-변수-및-스토리지" aria-label="Permalink to &quot;구성, 환경 변수 및 스토리지&quot;">​</a></h2><ul><li><strong>구성 디렉터리:</strong> <code>~/.openclaw</code></li><li><strong>작업 공간 디렉터리:</strong> <code>~/.openclaw/workspace</code></li><li><strong>토큰 파일:</strong> <code>~/.openclaw/.env</code></li><li><strong>실행 헬퍼:</strong> <code>./scripts/run-openclaw-podman.sh</code></li></ul><p>실행 스크립트와 Quadlet은 호스트 상태를 컨테이너에 바인드 마운트합니다:</p><ul><li><code>OPENCLAW_CONFIG_DIR</code> -&gt; <code>/home/node/.openclaw</code></li><li><code>OPENCLAW_WORKSPACE_DIR</code> -&gt; <code>/home/node/.openclaw/workspace</code></li></ul><p>기본적으로 이것들은 익명 컨테이너 상태가 아닌 호스트 디렉터리이므로 <code>openclaw.json</code>, 에이전트별 <code>auth-profiles.json</code>, 채널/제공자 상태, 세션 및 작업 공간은 컨테이너 교체 후에도 살아남습니다. Podman 설정은 컨테이너의 비루프백 바인드와 함께 로컬 대시보드가 작동하도록 게시된 게이트웨이 포트의 <code>127.0.0.1</code> 및 <code>localhost</code>에 대해 <code>gateway.controlUi.allowedOrigins</code>도 시드합니다.</p><p>수동 실행기에 유용한 환경 변수:</p><ul><li><code>OPENCLAW_PODMAN_CONTAINER</code> -- 컨테이너 이름 (기본값 <code>openclaw</code>)</li><li><code>OPENCLAW_PODMAN_IMAGE</code> / <code>OPENCLAW_IMAGE</code> -- 실행할 이미지</li><li><code>OPENCLAW_PODMAN_GATEWAY_HOST_PORT</code> -- 컨테이너 <code>18789</code>에 매핑되는 호스트 포트</li><li><code>OPENCLAW_PODMAN_BRIDGE_HOST_PORT</code> -- 컨테이너 <code>18790</code>에 매핑되는 호스트 포트</li><li><code>OPENCLAW_PODMAN_PUBLISH_HOST</code> -- 게시된 포트의 호스트 인터페이스; 기본값은 <code>127.0.0.1</code></li><li><code>OPENCLAW_GATEWAY_BIND</code> -- 컨테이너 내부의 게이트웨이 바인드 모드; 기본값은 <code>lan</code></li><li><code>OPENCLAW_PODMAN_USERNS</code> -- <code>keep-id</code> (기본값), <code>auto</code> 또는 <code>host</code></li></ul><p>수동 실행기는 컨테이너/이미지 기본값을 확정하기 전에 <code>~/.openclaw/.env</code>를 읽으므로 그곳에 유지할 수 있습니다.</p><p>기본값이 아닌 <code>OPENCLAW_CONFIG_DIR</code> 또는 <code>OPENCLAW_WORKSPACE_DIR</code>을 사용하는 경우 <code>./scripts/podman/setup.sh</code>와 이후 <code>./scripts/run-openclaw-podman.sh launch</code> 명령 모두에 동일한 변수를 설정합니다. 저장소 로컬 실행기는 셸 간에 사용자 정의 경로 재정의를 지속하지 않습니다.</p><p>Quadlet 참고 사항:</p><ul><li>생성된 Quadlet 서비스는 의도적으로 고정되고 강화된 기본 형태를 유지합니다: <code>127.0.0.1</code> 게시 포트, 컨테이너 내부에 <code>--bind lan</code>, <code>keep-id</code> 사용자 네임스페이스.</li><li><code>OPENCLAW_NO_RESPAWN=1</code>, <code>Restart=on-failure</code> 및 <code>TimeoutStartSec=300</code>을 고정합니다.</li><li><code>127.0.0.1:18789:18789</code> (게이트웨이)와 <code>127.0.0.1:18790:18790</code> (브리지)를 모두 게시합니다.</li><li><code>OPENCLAW_GATEWAY_TOKEN</code>과 같은 값을 위해 런타임 <code>EnvironmentFile</code>로 <code>~/.openclaw/.env</code>를 읽지만 수동 실행기의 Podman 특정 재정의 허용 목록을 소비하지 않습니다.</li><li>사용자 정의 게시 포트, 게시 호스트 또는 다른 컨테이너 실행 플래그가 필요한 경우 수동 실행기를 사용하거나 <code>~/.config/containers/systemd/openclaw.container</code>를 직접 편집한 다음 서비스를 다시 로드하고 재시작합니다.</li></ul><h2 id="유용한-명령어" tabindex="-1">유용한 명령어 <a class="header-anchor" href="#유용한-명령어" aria-label="Permalink to &quot;유용한 명령어&quot;">​</a></h2><ul><li><strong>컨테이너 로그:</strong> <code>podman logs -f openclaw</code></li><li><strong>컨테이너 중지:</strong> <code>podman stop openclaw</code></li><li><strong>컨테이너 제거:</strong> <code>podman rm -f openclaw</code></li><li><strong>호스트 CLI에서 대시보드 URL 열기:</strong> <code>openclaw dashboard --no-open</code></li><li><strong>호스트 CLI를 통한 헬스/상태:</strong> <code>openclaw gateway status --deep</code> (RPC 프로브 + 추가 서비스 스캔)</li></ul><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><ul><li><strong>구성 또는 작업 공간에서 권한 거부 (EACCES):</strong> 컨테이너는 기본적으로 <code>--userns=keep-id</code> 및 <code>--user &amp;lt;your uid&amp;gt;:&amp;lt;your gid&amp;gt;</code>로 실행됩니다. 호스트 구성/작업 공간 경로가 현재 사용자 소유인지 확인합니다.</li><li><strong>게이트웨이 시작 차단 (<code>gateway.mode=local</code> 누락):</strong> <code>~/.openclaw/openclaw.json</code>이 존재하고 <code>gateway.mode=&quot;local&quot;</code>을 설정하는지 확인합니다. <code>scripts/podman/setup.sh</code>가 없는 경우 이를 생성합니다.</li><li><strong>컨테이너 CLI 명령이 잘못된 대상에 도달:</strong> <code>openclaw --container &amp;lt;name&amp;gt; ...</code>을 명시적으로 사용하거나 셸에서 <code>OPENCLAW_CONTAINER=&amp;lt;name&amp;gt;</code>을 내보냅니다.</li><li><strong><code>openclaw update</code>가 <code>--container</code>와 함께 실패:</strong> 예상된 동작입니다. 이미지를 재빌드/가져온 다음 컨테이너 또는 Quadlet 서비스를 재시작합니다.</li><li><strong>Quadlet 서비스가 시작되지 않음:</strong> <code>systemctl --user daemon-reload</code>, 그런 다음 <code>systemctl --user start openclaw.service</code>를 실행합니다. 헤드리스 시스템에서는 <code>sudo loginctl enable-linger &quot;$(whoami)&quot;</code>도 필요할 수 있습니다.</li><li><strong>SELinux가 바인드 마운트를 차단:</strong> 기본 마운트 동작을 그대로 두십시오. 실행기는 SELinux가 강제 적용 또는 허용 모드일 때 Linux에서 자동으로 <code>:Z</code>를 추가합니다.</li></ul><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/install/docker">Docker</a></li><li><a href="/openclaw-docs-ko/gateway/background-process">게이트웨이 백그라운드 프로세스</a></li><li><a href="/openclaw-docs-ko/gateway/troubleshooting">게이트웨이 문제 해결</a></li></ul>`,65)])])}const g=a(l,[["render",d]]);export{u as __pageData,g as default};
